import React from 'react'
import type { TransitionStatus } from 'react-transition-group'
import {
  Transition as ReactTransition,
  TransitionGroup,
} from 'react-transition-group'

const timeout = 500
const transitionStylesMap: Record<
  TransitionStatus,
  React.CSSProperties | undefined
> = {
  entering: {
    position: 'absolute',
    opacity: 0,
  },
  entered: {
    transition: `opacity ${timeout}ms ease-in-out`,
    opacity: 1,
  },
  exiting: {
    transition: `all ${timeout}ms ease-in-out`,
    opacity: 0,
  },
  exited: undefined,
  unmounted: undefined,
}

interface TransitionProps {
  children: React.ReactNode
  location: {
    key: string
    pathname: string
  }
}

function Transition(props: TransitionProps): React.ReactElement {
  const { children, location } = props

  return (
    <TransitionGroup>
      <ReactTransition
        key={location.pathname}
        timeout={{
          enter: timeout,
          exit: timeout,
        }}
      >
        {status => (
          <div
            style={{
              ...transitionStylesMap[status],
            }}
          >
            {children}
          </div>
        )}
      </ReactTransition>
    </TransitionGroup>
  )
}

export default Transition
